sql.where:
o.deleted = 0

    AND o.order_no LIKE concat('%', #{orderNo}, '%')


    AND (o.member_name LIKE concat('%', #{memberKeyword}, '%')
         OR o.member_mobile LIKE concat('%', #{memberKeyword}, '%'))


    AND o.store_id = #{storeId}


    AND o.marketing_type = #{marketingType}


    AND o.order_status = #{orderStatus}



    AND o.created_at >= #{startTime}


    AND o.created_at < DATE_ADD(#{endTime}, INTERVAL 1 DAY)



    AND o.store_id IN (${storeIds})

mapper.select:
SELECT FROM pt_private_order o LEFT JOIN store s ON s.storeId = o.store_id LEFT JOIN pt_member_private_benefit b ON b.order_id = o.id
ORDER BY o.created_at DESC, o.id DESC
LIMIT #{offset}, #{limit}
